// portal-a13-gastos-listado — validar_firma_ts_rol.
// Recomputa HMAC-SHA256 sobre los bytes EXACTOS (D-C-29). Revalida ts (300s), rol
// (allowlist, D-C-39), action binding (D-C-41) y -A13- el payload de gastos.listado.
const crypto = require('crypto');

const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('VITA_HMAC_SECRET no configurado en n8n Variables; abortando (assert duro).');
}

const item = $input.first();
const wh = item.json;

function rej(motivo, b) {
  return [{ json: { ok_firma: false, motivo,
    ambiente_esperado: (b && b.ambiente_esperado) ?? null,
    rol: (b && b.rol) ?? null, action: (b && b.action) ?? null,
    ts: (b && b.ts) ?? null, payload_norm: null } }];
}

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody (L-C-05).
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) return rej('raw_body_ausente', null);

// 2) Firma del header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe.
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) return rej('firma_invalida', null);

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return rej('payload_invalido', null);
}

// 6) Ventana de ts (D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return rej('ts_fuera_de_ventana', { ...body, ts: body.ts });
}
body.ts = ts;

// 7) Allowlist de rol (D-C-39). A13 = vicky/socio (sin jenny, D-C-03).
const ROLES_OK = ['vicky', 'socio'];
if (!ROLES_OK.includes(body.rol)) return rej('rol_no_permitido', body);

// 8) Action binding (D-C-41): EXPECTED_ACTION = gastos.listado (A13).
const EXPECTED_ACTION = 'gastos.listado';
if (body.action !== EXPECTED_ACTION) return rej('accion_desconocida', body);

// 9) Payload A13. Reject-unknown + normalizacion.
//    Eje = periodo CONTABLE (dia 1). periodo_desde/periodo_hasta se TRUNCAN a primer dia
//    de mes (D1): un borde a mitad de mes incluye el mes completo. Floor 2026-07-01
//    (D-NEG-02) clampea periodo_desde (el SQL ademas lo impone con GREATEST).
//    periodo_hasta HIBRIDO:
//      - OMITIDO -> mes actual (primer dia del mes de hoy). SIN check de inversion: con
//        floor futuro queda periodo_desde>periodo_hasta -> la query devuelve vacio ok:true.
//      - EXPLICITO -> YMD valido y, truncado y tras el clamp, >= periodo_desde; sino payload_invalido.
//    Filtros opcionales (ausente/null = sin filtro, sin sentinela): clase {A,C,D,E},
//    id_zona/id_cabana (entero seguro >0), pagador_tipo {socio,caja}, q (string 1..120, ILIKE).
const FLOOR = '2026-07-01';
const PERMITIDAS = ['periodo_desde', 'periodo_hasta', 'clase', 'id_zona', 'id_cabana', 'pagador_tipo', 'q', 'limit', 'offset'];

let pl = {};
if (body.payload === undefined || body.payload === null) {
  pl = {};
} else if (typeof body.payload === 'object' && !Array.isArray(body.payload)) {
  pl = body.payload;
} else {
  return rej('payload_invalido', body);
}
for (const k of Object.keys(pl)) {
  if (!PERMITIDAS.includes(k)) return rej('payload_invalido', body);
}

function isYMD(s) {
  if (typeof s !== 'string' || !/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
  const Y = +s.slice(0, 4), M = +s.slice(5, 7), D = +s.slice(8, 10);
  if (M < 1 || M > 12 || D < 1 || D > 31) return false;
  const dt = new Date(Date.UTC(Y, M - 1, D));
  return dt.getUTCFullYear() === Y && dt.getUTCMonth() === M - 1 && dt.getUTCDate() === D;
}
function firstOfMonth(s) { return s.slice(0, 8) + '01'; }            // YYYY-MM-01 (D1)
function thisMonthYMD() { return new Date().toISOString().slice(0, 8) + '01'; }

// periodo_desde: opcional; YMD; truncado a mes; clamp al floor. Default = floor (ya dia 1).
let periodo_desde = FLOOR;
if (pl.periodo_desde !== undefined && pl.periodo_desde !== null) {
  if (!isYMD(pl.periodo_desde)) return rej('payload_invalido', body);
  const d1 = firstOfMonth(pl.periodo_desde);
  periodo_desde = (d1 < FLOOR) ? FLOOR : d1;
}

// periodo_hasta: hibrido. Truncado a mes. Inversion solo si EXPLICITO (a nivel mes).
let periodo_hasta;
const hastaExplicito = (pl.periodo_hasta !== undefined && pl.periodo_hasta !== null);
if (hastaExplicito) {
  if (!isYMD(pl.periodo_hasta)) return rej('payload_invalido', body);
  const h1 = firstOfMonth(pl.periodo_hasta);
  if (h1 < periodo_desde) return rej('payload_invalido', body); // inversion explicita
  periodo_hasta = h1;
} else {
  periodo_hasta = thisMonthYMD(); // floor futuro -> periodo_desde>periodo_hasta -> vacio OK
}

// clase: opcional; enum {A,C,D,E}. Ausente/null = sin filtro.
const CLASES_OK = ['A', 'C', 'D', 'E'];
let clase;
if (pl.clase !== undefined && pl.clase !== null) {
  if (typeof pl.clase !== 'string' || !CLASES_OK.includes(pl.clase)) return rej('payload_invalido', body);
  clase = pl.clase;
}

// id_zona / id_cabana: opcional; entero seguro > 0. Ausente/null = sin filtro.
function idOpt(v) {
  if (v === undefined || v === null) return undefined;                 // sin filtro
  if (typeof v !== 'number' || !Number.isSafeInteger(v) || v <= 0) return null; // invalido
  return v;
}
const id_zona = idOpt(pl.id_zona);
if (id_zona === null) return rej('payload_invalido', body);
const id_cabana = idOpt(pl.id_cabana);
if (id_cabana === null) return rej('payload_invalido', body);

// pagador_tipo: opcional; enum {socio,caja}. Ausente/null = sin filtro.
const PAGADOR_OK = ['socio', 'caja'];
let pagador_tipo;
if (pl.pagador_tipo !== undefined && pl.pagador_tipo !== null) {
  if (typeof pl.pagador_tipo !== 'string' || !PAGADOR_OK.includes(pl.pagador_tipo)) return rej('payload_invalido', body);
  pagador_tipo = pl.pagador_tipo;
}

// q: opcional; string trim 1..120. Ausente/null = sin filtro. Vacio/oversized -> payload_invalido.
let q;
if (pl.q !== undefined && pl.q !== null) {
  if (typeof pl.q !== 'string') return rej('payload_invalido', body);
  const qt = pl.q.trim();
  if (qt.length < 1 || qt.length > 120) return rej('payload_invalido', body);
  q = qt;
}

// limit: opcional; entero; clamp [1,200]; default 50.
let limit = 50;
if (pl.limit !== undefined && pl.limit !== null) {
  if (typeof pl.limit !== 'number' || !Number.isSafeInteger(pl.limit)) return rej('payload_invalido', body);
  limit = Math.min(Math.max(pl.limit, 1), 200);
}

// offset: opcional; entero >= 0; default 0.
let offset = 0;
if (pl.offset !== undefined && pl.offset !== null) {
  if (typeof pl.offset !== 'number' || !Number.isSafeInteger(pl.offset) || pl.offset < 0) return rej('payload_invalido', body);
  offset = pl.offset;
}

// payload_norm: los filtros presentes se incluyen; los ausentes NO van (el SQL usa IS NULL).
const payload_norm = { periodo_desde, periodo_hasta, limit, offset };
if (clase !== undefined) payload_norm.clase = clase;
if (id_zona !== undefined) payload_norm.id_zona = id_zona;
if (id_cabana !== undefined) payload_norm.id_cabana = id_cabana;
if (pagador_tipo !== undefined) payload_norm.pagador_tipo = pagador_tipo;
if (q !== undefined) payload_norm.q = q;

return [{ json: { ok_firma: true, motivo: null,
  ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null,
  action: body.action ?? null, ts, payload_norm } }];

// portal-a13-gastos-listado — verificar_acceso. Compara ambiente y arma el envelope de
// rechazo (D-C-18/35). En exito marca {ok:true}; el envelope final de exito lo arma el render.
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'payload invalido (periodo/filtro mal formado, inversion explicita o clave no permitida)',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

return [{ json: { ok: true } }];

// ===== portal-a13-gastos-listado — render JSON (gastos por periodo) =====
// total_gastos = SUM(monto) sobre el universo FILTRADO COMPLETO, en CENTAVOS (sin float drift).
// por_clase = [{clase, monto, n}] sobre el universo completo (NO solo la pagina). filas paginadas.
// IDs BIGINT -> numero (L-C-19). Universo vacio -> total 0, por_clase [], filas [], ok:true.
// NOTA: los agregados monetarios asumen moneda homogenea del sistema operativo MVP.
function safeAll(nodeName, keyField) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    const rows = items.map(it => it.json).filter(j => j && j[keyField] !== undefined && j[keyField] !== null);
    return { ok: true, rows };
  } catch (e) { return { ok: false, rows: [] }; }
}
function num(v) { if (v === null || v === undefined || v === '') return null; const n = Number(v); return Number.isFinite(n) ? n : null; }
function int0(v) { const n = Number(v); return Number.isFinite(n) ? Math.trunc(n) : 0; }
function intN(v) { if (v === null || v === undefined) return null; const n = Number(v); return Number.isFinite(n) ? Math.trunc(n) : null; }
function centsOf(v) { const n = Number(v); return Number.isFinite(n) ? Math.round(n * 100) : 0; }

const r = safeAll('PG: leer gastos', 'id_gasto');
if (!r.ok) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar los gastos', detail: null } } }];
}

const pn = $('validar_firma_ts_rol').first().json.payload_norm || {};
const limit = int0(pn.limit);
const offset = int0(pn.offset);

// total_gastos (centavos) sobre el universo completo.
let totalC = 0;
for (const x of r.rows) totalC += centsOf(x.monto);
const total_gastos = totalC / 100;

// por_clase sobre el universo completo: [{clase, monto, n}].
const m = new Map();
for (const x of r.rows) {
  const k = x.clase;
  const cur = m.get(k) || { c: 0, n: 0 };
  cur.c += centsOf(x.monto);
  cur.n += 1;
  m.set(k, cur);
}
const por_clase = [];
for (const [k, v] of m) por_clase.push({ clase: k, monto: v.c / 100, n: v.n });

// filas paginadas, columnas lockeadas (20). BIGINT -> numero; opcionales null-safe.
const filasAll = r.rows.map(x => ({
  id_gasto: int0(x.id_gasto),
  periodo: x.periodo,
  fecha: x.fecha,
  clase: x.clase,
  clase_sugerida: x.clase_sugerida ?? null,
  etiqueta: x.etiqueta,
  monto: num(x.monto),
  moneda: x.moneda ?? null,
  pagador_tipo: x.pagador_tipo,
  id_socio_pagador: intN(x.id_socio_pagador),
  socio_pagador_nombre: x.socio_pagador_nombre ?? null,
  id_zona: intN(x.id_zona),
  zona: x.zona ?? null,
  id_cabana: intN(x.id_cabana),
  cabana: x.cabana ?? null,
  medio_pago: x.medio_pago ?? null,
  comentario: x.comentario ?? null,
  comprobante_url: x.comprobante_url ?? null,
  creado_por: x.creado_por,
  created_at: x.created_at
}));
const filas = filasAll.slice(offset, offset + limit);

return [{ json: { ok: true, data: {
  periodo_desde: pn.periodo_desde ?? null,
  periodo_hasta: pn.periodo_hasta ?? null,
  total_gastos,
  por_clase,
  filas,
  limit,
  offset
} } }];
